#include <bits/stdc++.h>
using namespace std;

bool isPrime[10000];

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    fill(isPrime, isPrime + 10000, true);
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i < 10000; i++) {
        if (isPrime[i]) {
            for (int j = 2 * i; j < 10000; j += i) isPrime[j] = false;
        }
    }
    int T;
    cin >> T;
    while (T--) {
        int A, B;
        cin >> A >> B;
        vector<int> dist(10000, -1);
        queue<int> q;
        q.push(A);
        dist[A] = 0;
        while (!q.empty()) {
            int cur = q.front(); q.pop();
            if (cur == B) break;
            int digits[4];
            digits[0] = cur / 1000;
            digits[1] = (cur / 100) % 10;
            digits[2] = (cur / 10) % 10;
            digits[3] = cur % 10;
            int place[4] = {1000, 100, 10, 1};
            for (int p = 0; p < 4; p++) {
                int startD = (p == 0) ? 1 : 0;
                for (int d = startD; d <= 9; d++) {
                    if (d == digits[p]) continue;
                    int nxt = cur + (d - digits[p]) * place[p];
                    if (isPrime[nxt] && dist[nxt] == -1) {
                        dist[nxt] = dist[cur] + 1;
                        q.push(nxt);
                    }
                }
            }
        }
        if (dist[B] == -1) cout << "Impossible\n";
        else cout << dist[B] << "\n";
    }
    return 0;
}
